                        onClick={() => setSelectedCategory(category.categoryId)}
                    />
                </div>
            ))}
        </div>
    );
};

export default DisplayCategory;

import {useContext, useState} from 'react';
import { AppContext } from '../../context/AppContext';
import Item from '../Item/Item';
import './DisplayItems.css';
import SearchBox from "../SearchBox/SearchBox.jsx";

const DisplayItems = ({selectedCategory}) => {
    const { itemsData } = useContext(AppContext);
    const [searcheText , setSearchText] = useState("");
    const filteredItems = itemsData.filter(item => {
        if(!selectedCategory) return true;
        return item.category === selectedCategory;
    }).filter(item => item.name.toLowerCase().includes(searcheText.toLowerCase()));

    return (
        <div className="p-3">
            <div className="d-flex justify-content-between align-items-center mb-4">
                <div></div>
                <div>
                    <SearchBox onSearch={setSearchText}
                    />
                </div>

            </div>
            <div className="row g-3">
                {filteredItems.map((item, index) => (
                    <div
                        key={index}
                        className="col-md-4 col-sm-6"
                    >
                        <Item
                            itemName={item.name}
                            itemPrice={item.price}
                            itemImage={item.imgUrl}
                            itemId={item.itemId}
                        />
                    </div>
                ))}
            </div>
        </div>
    );
};

export default DisplayItems;

import {useContext, useState} from 'react';
import { AppContext } from '../../context/AppContext';
import Item from '../Item/Item';
import './DisplayItems.css';
import SearchBox from "../SearchBox/SearchBox.jsx";

const DisplayItems = ({selectedCategory}) => {
    const { itemsData } = useContext(AppContext);
    const [searcheText , setSearchText] = useState("");
    const filteredItems = itemsData.filter(item => {
        if(!selectedCategory) return true;
        return String(item.categoryId) === String(selectedCategory);
    }).filter(item => item.name.toLowerCase().includes(searcheText.toLowerCase()));

    return (
        <div className="p-3">
            <div className="d-flex justify-content-between align-items-center mb-4">
                <div></div>
                <div>
                    <SearchBox onSearch={setSearchText}
                    />
                </div>

            </div>
            <div className="row g-3">
                {filteredItems.map((item, index) => (
                    <div
                        key={index}
                        className="col-md-4 col-sm-6"
                    >
                        <Item
                            itemName={item.name}
                            itemPrice={item.price}
                            itemImage={item.imgUrl}
                            itemId={item.itemId}
                        />
                    </div>
                ))}
            </div>
        </div>
    );
};

export default DisplayItems;

import './Explore.css'
import {useContext} from "react";
import {AppContext} from "../../context/AppContext.jsx";
import DisplayCategory from "../../components/DisplayCategory/DisplayCategory.jsx";
import DisplayItems from "../../components/DisplayItems/DisplayItems.jsx";
import CustomerFrom from "../../components/CustomerForm/CustomerFrom.jsx";
import CartItems from "../../components/CartItems/CartItems.jsx";
import CartSummary from "../../components/CartSummary/CartSummary.jsx";
import {useState} from "react";
const Explore = () => {
    const {categories} = useContext(AppContext);
    const [selectedCategory, setSelectedCategory] = useState("");
    return (
        <div className="explore-container text-light">

            {/* LEFT SIDE */}
            <div className="left-column">

                <div
                    className="first-row"
                    style={{ overflowY: "auto" }}
                >
                    <DisplayCategory
                        selectedCategory={selectedCategory}
                        setSelectedCategory={setSelectedCategory}
                        categories={categories} />
                </div>

                <hr className="horizontal-line" />

                <div
                    className="second-row"
                    style={{ overflowY: "auto" }}
                >
                    <DisplayItems selectedCategory={selectedCategory}/>
                </div>

            </div>

            {/* RIGHT SIDE */}
            <div className="right-column d-flex flex-column h-100">

                <div
                    className="customer-form-container"
                    style={{ height: "15%" }}
                >
                    <CustomerFrom />
                </div>

                <hr className="my-3" />

                <div
                    className="cart-items-container"
                    style={{ height: "55%", overflowY: "auto" }}
                >
                    <CartItems />
                </div>

                <div
                    className="cart-summary-container"
                    style={{ height: "30%" }}
                >
                    <CartSummary />
                </div>

            </div>

        </div>
    );
};

export default Explore;

